          type: 'outgoing',
          typeCategory: null,
          description: 'Misc',
          transactionDate: utc(currentYear, 5, 1),
        },
      ]);

      const response = await request(createApp())
        .get(`/financial/dashboard?month=${monthQuery(5)}`)
