64	// Progress is a 0–100 score representing where a month sits within the
65	// disposable-income range of the current window: best month → 100, worst → 0.
66	// It is intentionally relative — it surfaces the customer's own trajectory
67	// rather than judging them against an absolute threshold.
68	export const calculateProgressForWindow = (disposableIncomes: number[]): number[] => {
69	  if (disposableIncomes.length === 0) {
70	    return [];
71	  }
72	  if (disposableIncomes.length === 1) {
73	    return [disposableIncomes[0] > 0 ? 100 : 0];
74	  }
75	  const min = Math.min(...disposableIncomes);
76	  const max = Math.max(...disposableIncomes);
77	  if (min === max) {
78	    return disposableIncomes.map(() => 50);
79	  }
80	  const range = max - min;
81	  return disposableIncomes.map((d) => Math.round(((d - min) / range) * 100));
82	};
