91	  const oldestMonth = subMonths(mostRecentMonth, lookbackMonths - 1);
92	  return Array.from({ length: lookbackMonths }, (_, offset) => ({
93	    monthStart: addMonths(oldestMonth, offset),
94	    totalIncome: 0,
95	    totalExpenditure: 0,
96	  }));
