      expect(response.body.yourMoneyThisMonth.outgoing.sections).toEqual([
        {
          sectionKey: 'other',
          sectionLabel: 'Other',
          subtotal: 75,
          items: [{ description: 'Misc', amount: 75 }],
        },
      ]);
    });
  });
});

